function secondsToSrtTime(seconds) {
  const hrs = Math.floor(seconds / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);
  const ms = Math.round((seconds - Math.floor(seconds)) * 1000);

  return (
    String(hrs).padStart(2, '0') + ':' +
    String(mins).padStart(2, '0') + ':' +
    String(secs).padStart(2, '0') + ',' +
    String(ms).padStart(3, '0')
  );
}


function splitTextSmart(text, minLen = 20, maxLen = 30) {
  const punctuationRegex = /([.!?])/g;


  const chunks = text
    .replace(punctuationRegex, '$1|')
    .split('|')
    .map(t => t.trim())
    .filter(Boolean);

  let result = [];

  for (const chunk of chunks) {
    if (chunk.length <= maxLen) {
      result.push(chunk);
    } else {

      const words = chunk.split(' ');
      let line = '';

      for (const word of words) {
        if ((line + ' ' + word).trim().length > maxLen) {
          result.push(line.trim());
          line = word;
        } else {
          line += ' ' + word;
        }
      }
      if (line.trim()) result.push(line.trim());
    }
  }

  return result;
}


let input = items[0].json;
if (!Array.isArray(input)) input = [input];

let srt = '';
let index = 1;

for (const segment of input) {
  if (!segment.words || !Array.isArray(segment.words)) continue;

  const words = segment.words.filter(w => w.type === 'word');
  if (!words.length) continue;

  const fullText = segment.text?.trim();
  if (!fullText) continue;

  const start = words[0].start;
  const end = words[words.length - 1].end;
  const totalDuration = end - start;


  const textParts = splitTextSmart(fullText);

  const partDuration = totalDuration / textParts.length;

  textParts.forEach((part, i) => {
    const partStart = start + partDuration * i;
    const partEnd = partStart + partDuration;

    srt += `${index}\n`;
    srt += `${secondsToSrtTime(partStart)} --> ${secondsToSrtTime(partEnd)}\n`;
    srt += `${part}\n\n`;
    index++;
  });
}

return [
  {
    json: {
      srt
    }
  }
];

